def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 3:
            base_score = 3000 + 70 * (ratio - 3) ** 4
        elif ratio > 2:
            base_score = 1800 + 60 * (ratio - 2) ** 3
        elif ratio > 1:
            base_score = 1200 + 30 * (ratio - 1) ** 2
        else:
            if ratio > 0.95:
                base_score = 100 * ratio + 25
            elif ratio > 0.8:
                base_score = 60 * ratio + 15
            elif ratio > 0.5:
                base_score = 30 * ratio + 8
            else:
                base_score = 10 * ratio + 2
            if capacity < 3:
                base_score += 30
            elif capacity < 15:
                base_score += 15
            elif capacity > 100:
                base_score -= 20
        modifier = 1.0
        if i % 4 == 0:
            modifier += 0.2
            if ratio < 0.3:
                modifier += 0.1
            if capacity % 5 == 0:
                modifier += 0.05
        elif i % 4 == 1:
            modifier -= 0.15
            if ratio > 1.8:
                modifier -= 0.1
        elif i % 4 == 2:
            modifier += 0.1
            if capacity % 3 == 1:
                modifier += 0.07
        else:
            modifier -= 0.05
            if ratio > 1.2 and ratio < 1.5:
                modifier += 0.03
        adjusted_score = base_score * modifier
        window_start = max(0, i - 3)
        window_end = min(n, i + 4)
        neighbor_diffs = []
        for j in range(window_start, window_end):
            if j != i and bins[j] > 0:
                diff = abs(item - bins[j])
                if diff > capacity * 0.7:
                    adjusted_score += diff * 0.1
                else:
                    adjusted_score -= diff * 0.05
                neighbor_diffs.append(diff)
        if neighbor_diffs:
            median_diff = np.median(neighbor_diffs)
            if median_diff < capacity * 0.4:
                adjusted_score *= 0.75
            elif median_diff > capacity * 0.8:
                adjusted_score *= 1.3
        if i > 0 and i < n - 1:
            left = bins[i - 1]
            right = bins[i + 1]
            if left > capacity and right > capacity:
                adjusted_score *= 0.85
            elif left < capacity and right < capacity:
                adjusted_score *= 1.1
        if ratio < 0.1:
            adjusted_score += 5 * np.exp(-capacity / 50)
        priorities[i] = adjusted_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fallback = 10
    else:
        fallback = np.min(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = fallback + 120
    for i in range(n):
        if priorities[i] < 30:
            priorities[i] += 15 * (item / (bins[i] + 1)) + 0.5 * i
    return priorities
